                </AboutFeature>
                <AboutFeature>
                  <span className="icon">📈</span>
                  <div>
                    <strong>Investments</strong>
                    <span>Strategic growth</span>
                  </div>
                </AboutFeature>
                <AboutFeature>
                  <span className="icon">🌐</span>
                  <div>
                    <strong>Global Trade</strong>
                    <span>Worldwide reach</span>
                  </div>
                </AboutFeature>
                <AboutFeature>
                  <span className="icon">🤝</span>
                  <div>
                    <strong>Partnerships</strong>
                    <span>Long-term relations</span>
                  </div>
                </AboutFeature>
              </AboutFeatures>
            </AboutText>
          </AboutGrid>
        </Container>
      </Section>

      <Section $variant="cream">
        <Container>
          <SectionTitle
            eyebrow="Our Journey"
            title="Growth Through the Years"
            subtitle="From a focused vision to a diversified group, every milestone reflects our commitment to excellence and sustainable progress."
          />

          <TimelineGrid>
            <TimelineColumn>
              {timelineItems.slice(0, 2).map((item) => (
                <TimelineItem key={item.title}>
                  <div className="year">{item.year}</div>
                  <h3>{item.title}</h3>
                  <p>{item.text}</p>
                </TimelineItem>
              ))}
            </TimelineColumn>
            <TimelineColumn>
              {timelineItems.slice(2).map((item) => (
                <TimelineItem key={item.title}>
                  <div className="year">{item.year}</div>
                  <h3>{item.title}</h3>
                  <p>{item.text}</p>
                </TimelineItem>
              ))}
            </TimelineColumn>
          </TimelineGrid>
        </Container>
      </Section>

      <Section id="companies">
        <Container>
          <SectionTitle
            eyebrow="Group Companies"
            title="Our Business Subsidiaries"
            subtitle="Four specialized companies working in concert to deliver comprehensive solutions across construction, investment, and global trade."
          />

          <CompaniesGrid>
            {companyCards.map((company) => (
              <CompanyCard key={company.id}>
                <div className="number">{company.id}</div>
                <div className="icon">{company.id === '02' ? '📊' : company.id === '03' ? '🌍' : company.id === '04' ? '📦' : '🏗️'}</div>
                <h3>{company.title}</h3>
                <p>{company.text}</p>
                <CompanyTags>
                  {company.tags.map((tag) => (
                    <span key={tag}>{tag}</span>
                  ))}
                </CompanyTags>
                <CompanyLink href="#contact">Learn More →</CompanyLink>
              </CompanyCard>
            ))}
          </CompaniesGrid>
        </Container>
      </Section>

      <Section id="why" $variant="dark">
        <Container>
          <SectionTitle
            light
            eyebrow="Why Choose Us"
            title="The Lucky Group Advantage"
            subtitle="We combine global reach with local understanding, backed by experienced professionals who put client success at the heart of everything we do."
          />

          <WhyGrid>
            {advantageItems.map((item) => (
              <FeatureCard key={item.title}>
                <div className="icon">{item.icon}</div>
                <h3>{item.title}</h3>
                <p>{item.text}</p>
              </FeatureCard>
            ))}
          </WhyGrid>
        </Container>
      </Section>

      <Section $variant="cream">
        <Container>
          <SectionTitle eyebrow="Our Purpose" title="Vision & Mission" />

          <MissionGrid>
            <MissionCard>
              <div className="bg-letter">V</div>
              <div className="label">Our Vision</div>
              <h3>To become a trusted global business group creating sustainable growth.</h3>
              <p>
                We aspire to be recognized worldwide as a diversified business group that delivers excellence across
                every industry we operate in — setting benchmarks for quality, trust, and innovation that benefit
                clients, partners, and communities alike.
              </p>
            </MissionCard>
            <MissionCard $variant="gold">
              <div className="bg-letter">M</div>
              <div className="label">Our Mission</div>
              <h3>To provide innovative solutions and foster long-term relationships.</h3>
              <p>
                Our mission is to deliver innovative, reliable, and value-driven solutions across construction,
                investment, and trade — while contributing meaningfully to economic growth and community development
                through ethical business practices.
              </p>
            </MissionCard>
          </MissionGrid>
        </Container>
      </Section>

      <Section id="contact">
        <Container>
          <SectionTitle
            eyebrow="Get In Touch"
            title="Contact Lucky Group"
            subtitle="Whether you're a client, investor, or business partner — we'd love to hear from you. Reach out and our team will respond promptly."
          />

          <ContactPanel>
            <ContactOverview>
              <h3>Formal Contact Details</h3>
              <p>Use the details below to reach our office by phone, email, or mail. We keep all communication direct, professional, and easy to access.</p>
            </ContactOverview>

            <ContactDetailsGrid>
              {contactItems.map((item) => (
                <ContactDetailCard key={item.label}>
                  <div className="top">
                    <div className="icon">{item.icon}</div>
                    <div>
                      <span>{item.label}</span>
                      <strong>{item.title}</strong>
                    </div>
                  </div>
                  <div className="copy">{item.copy}</div>
                  <div className="meta">{item.meta.join('\n')}</div>
                </ContactDetailCard>
              ))}
            </ContactDetailsGrid>
          </ContactPanel>
        </Container>
      </Section>

      <Footer>
        <FooterGrid>
          <FooterBrand>
            <a className="logo" href="#home" style={{ textDecoration: 'none' }}>
              <span className="mark">L</span>
              <span className="text">
                <span>Lucky Group</span>
                <span>of Companies</span>
              </span>
            </a>
            <p>
              A diversified business group delivering excellence across construction, investments, and global trade.
              Building trust, creating value, and driving sustainable growth.
            </p>
            <FooterSocial>
              <SocialBtn href="#" title="Facebook">f</SocialBtn>
              <SocialBtn href="#" title="LinkedIn">in</SocialBtn>
              <SocialBtn href="#" title="Instagram">ig</SocialBtn>
              <SocialBtn href="#" title="YouTube">yt</SocialBtn>
            </FooterSocial>
          </FooterBrand>

          <FooterCol>
            <h4>Quick Links</h4>
            <ul>
              <li><a href="#home">Home</a></li>
              <li><a href="#about">About Us</a></li>
              <li><a href="#companies">Group Companies</a></li>
              <li><a href="#contact">Contact Us</a></li>
            </ul>
          </FooterCol>

          <FooterCol>
            <h4>Group Companies</h4>
            <ul>
              <li><a href="#companies">Lucky Builders & Development</a></li>
              <li><a href="#companies">Lucky Global Holdings Ltd.</a></li>
              <li><a href="#companies">Eraj Global Trading SMC</a></li>
              <li><a href="#companies">Lucky Global Traders</a></li>
            </ul>
          </FooterCol>

          <FooterCol>
            <h4>Contact</h4>
            <ul>
              <li><a href="tel:+923000000000">+92 300 0000000</a></li>
              <li><a href="mailto:info@luckygroup.com">info@luckygroup.com</a></li>
              <li><a href="#contact">Lahore, Pakistan</a></li>
              <li><a href="#contact">Mon–Sat, 9AM–6PM</a></li>
            </ul>
          </FooterCol>
        </FooterGrid>

        <FooterBottom>
          <p>© 2026 Lucky Group of Companies. All Rights Reserved.</p>
          <p>Designed with excellence & care.</p>
        </FooterBottom>
      </Footer>
    </Page>
